public void testCloseWithFinishException() throws IOException {
    File testArchive = File.createTempFile("jar-close-test", ".jar");
    JarArchiveOutputStream out = null;
    try {
        out = new JarArchiveOutputStream(new FileOutputStream(testArchive));
        out.putArchiveEntry(new ZipArchiveEntry("test/"));
        out.closeArchiveEntry();
        // Do not call finish(), close should still work
        out.close();
        out = null;
        assertTrue(testArchive.exists());
    } finally {
        if (out != null) {
            try {
                out.close();
            } catch (IOException e) { /* swallow */ }
        }
        if (testArchive.exists()) {
            testArchive.delete();
        }
    }
}

public void testCloseAfterException() throws IOException {
    File file = File.createTempFile("close-test", ".zip");
    ZipArchiveOutputStream out = null;
    try {
        out = new ZipArchiveOutputStream(file);
        out.putArchiveEntry(new ZipArchiveEntry("test.txt"));
        out.write("test data".getBytes());
        out.closeArchiveEntry();
        out.close();
        out = null;
        assertTrue(file.exists());
    } finally {
        if (out != null) {
            try {
                out.close();
            } catch (IOException e) { /* swallow */ }
        }
        if (file.exists()) {
            file.delete();
        }
    }
}
